// Get Airtable data
const fields = $input.last().json;

// Parse and format the start date
const startDate = new Date(fields['VA Start Date']);
const startDateFormatted = startDate.toLocaleDateString('en-US', { 
  weekday: 'long', 
  year: 'numeric', 
  month: 'long', 
  day: 'numeric' 
});

// Calculate days until start
const now = new Date();
const daysUntilStart = Math.ceil((startDate - now) / (1000 * 60 * 60 * 24));

// Build subject line - SIMPLIFIED (removed VA name)
const vaName = fields['VA Name'] ? fields['VA Name'][0] : 'your Virtual Assistant';
const subject = `Scale Virtually: DocuSign Signature Required`;

// Get client and contact information
const clientName = fields['Client'] ? fields['Client'][0] : '';
const clientEmail = fields['Account Owner Email'] ? fields['Account Owner Email'][0] : '';
const pocEmail = fields['POC Email'] ? fields['POC Email'][0] : '';
const envelopeId = fields['Envelope ID'] || '';

// Build HTML email body with Scale Virtually colors
const htmlBody = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
    .container { max-width: 600px; margin: 0 auto; padding: 20px; }
    .header { 
      background: #F17D19; 
      color: #FFFFFF; 
      padding: 20px; 
      border-radius: 5px 5px 0 0;
      text-align: center;
    }
    .content { background: #FFFFFF; padding: 30px; border-radius: 0 0 5px 5px; border: 1px solid #e0e0e0; }
    .highlight { background: #FFF5ED; border-left: 4px solid #F17D19; padding: 15px; margin: 20px 0; }
    .info-box { background: #f8f9fa; border: 1px solid #6E86AD; border-radius: 5px; padding: 20px; margin: 20px 0; }
    .footer { margin-top: 30px; padding-top: 20px; border-top: 1px solid #6E86AD; font-size: 0.9em; color: #6E86AD; }
    .accent { color: #F17D19; font-weight: bold; }
    ul { margin: 10px 0; padding-left: 20px; }
    li { margin: 8px 0; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h2 style="margin: 0;">Friendly Reminder</h2>
    </div>

    <div class="content">
      <p>Hi ${clientName},</p>

      <p>We hope this email finds you well! We wanted to send a friendly reminder that we're still waiting for your signature on the VA Endorsement Form.</p>

      <div class="highlight">
        <strong>VA Name:</strong> ${vaName}<br>
        <strong>Expected Start Date:</strong> ${startDateFormatted}<br>
        <strong>Days Until Start:</strong> ${daysUntilStart} days
      </div>

      <p>To ensure ${vaName} can start on schedule, we need your signature as soon as possible. <strong class="accent">Without your signature, we will need to move the start date.</strong></p>

      <div class="info-box">
        <p style="margin-top: 0;"><strong style="color: #F17D19;">Please check your email for the DocuSign notification.</strong></p>

        <p>The signing process only takes about 2 minutes. Please check your email inbox for the DocuSign notification.</p>

        <p><strong>Subject line to look for:</strong> "Please DocuSign: SV Virtual Assistant Endorsement Form"</p>

        <p><strong>If you can't find the email:</strong></p>
        <ul>
          <li>Check your spam/junk folder</li>
          <li>Search your inbox for "DocuSign"</li>
          <li>Look for emails from "dse@docusign.net"</li>
        </ul>
      </div>

      <p>If you have any questions about the agreement or need any clarification, please don't hesitate to reach out. We're here to help make this process as smooth as possible!</p>

      <p>Looking forward to getting your VA started with your team!</p>

      <p>Best regards,<br>
      <strong style="color: #F17D19;">Scale Virtually Team</strong></p>

      <div class="footer">
        <p><em>Still can't find the DocuSign email? Reply to this email and we'll assist you right away.</em></p>
      </div>
    </div>
  </div>
</body>
</html>
`;

return {
  json: {
    recordId: fields['Record ID'],
    vaName: vaName,
    clientEmail: clientEmail,
    pocEmail: pocEmail,
    subject: subject,
    htmlBody: htmlBody,
    followUpType: 'first_reminder',
    envelopeId: envelopeId
  }
};

return items.map(item => {
  return {
    json: {
      emailSentAt: new Date().toISOString(),
      emailSentDate: new Date().toLocaleString('en-US', {
        timeZone: 'America/Chicago',
        year: 'numeric',
        month: '2-digit',
        day: '2-digit',
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit'
      }),
      recordId: $('Build 24hr Reminder Email').item.json.recordId,
      followUpType: $('Build 24hr Reminder Email').item.json.followUpType
    }
  };
});

return items.map(item => {
  const fields = item.json.fields || item.json;

  // Get the VA Start Date from Airtable
  const startDate = new Date(fields['VA Start Date']);
  const now = new Date();

  // Calculate when urgent reminder should be sent (24 hours before start)
  const urgentReminderTime = new Date(startDate.getTime() - (24 * 60 * 60 * 1000));

  // Calculate how long to wait from NOW until urgent reminder time
  const waitMilliseconds = urgentReminderTime - now;
  const waitHours = Math.max(0, Math.floor(waitMilliseconds / (1000 * 60 * 60)));

  // Calculate days until start (for display purposes)
  const hoursUntilStart = Math.floor((startDate - now) / (1000 * 60 * 60));
  const daysUntilStart = Math.ceil(hoursUntilStart / 24);

  // Format for n8n Wait node "At Specified Time"
  // Format: YYYY-MM-DD HH:mm:ss
  const urgentReminderDateTime = urgentReminderTime.toISOString().slice(0, 19).replace('T', ' ');

  return {
    json: {
      ...item.json,
      recordId: item.json.id || item.json.recordId,
      waitHours: waitHours,
      urgentReminderTime: urgentReminderTime.toISOString(),
      urgentReminderDateTime: urgentReminderDateTime,
      startDate: startDate.toISOString(),
      hoursUntilStart: hoursUntilStart,
      daysUntilStart: daysUntilStart,
      shouldSendUrgent: waitHours > 0,
      currentTime: now.toISOString()
    }
  };
});

